export interface StoryBook { ageMin: number; ageMax: number; title: string; author: string; theme: string; whyRead: string; genre: string }
export interface ToyActivity { ageMin: number; ageMax: number; name: string; category: 'cognitive'|'creative'|'physical'|'social'; benefit: string; examples: string[] }
export interface SportActivity { name: string; ageMin: number; ageMax: number; benefit: string; indoorOutdoor: 'indoor'|'outdoor'|'both'; skillBuilt: string; emoji: string }
export interface YouTubeChannel { name: string; subject: string; ageRange: string; description: string; language: 'English'|'Hindi'|'Both'; emoji: string; searchQuery: string }
export interface VocabWord { word: string; meaning: string; example: string; grade: number; difficulty: 'basic'|'intermediate'|'advanced' }
export interface Riddle { riddle: string; answer: string; ageGroup: '5-7'|'8-10'|'11-14'; category: 'logic'|'wordplay'|'science'|'math' }
export interface TongueTwister { text: string; difficulty: 'easy'|'medium'|'hard'; language: 'English'|'Hindi' }
export interface Poem { title: string; lines: string; theme: string; ageGroup: '5-8'|'9-12'; type: 'poem'|'phrase'|'quote' }
export interface FunFact { fact: string; category: 'history'|'science'|'nature'|'invention'|'world-record'|'India'; ageGroup: '6-9'|'10-14' }
export interface MindGame { name: string; description: string; ageMin: number; benefits: string[]; howToPlay: string; type: 'sudoku'|'puzzle'|'logic'|'memory'|'spatial'|'word' }

